UPDATE public.industry_template_packs SET kb_seed_documents = '[{"name":"HVAC - Services Overview","content":"Heating, ventilation, and AC services including repair, installation, heat pumps, ductwork, IAQ, thermostats, and maintenance plans. 24/7 emergency service available."},{"name":"HVAC - Pricing & Process","content":"Diagnostics $89-$149. Repairs $200-$800. New systems from $5,500. Financing and free replacement estimates. Maintenance plans from $189/yr.","faqs":[{"question":"How often should I service my HVAC?","answer":"Twice a year - heating tune-up in fall, AC tune-up in spring.","category":"general"},{"question":"How long do systems last?","answer":"AC 12-15 years; furnaces 15-20 years.","category":"general"},{"question":"Do you offer financing?","answer":"Yes, 0% APR on qualifying installs.","category":"general"},{"question":"Are you licensed and insured?","answer":"Yes, fully licensed, bonded, insured. EPA 608 certified.","category":"general"},{"question":"Do you provide emergency service?","answer":"Yes, 24/7 for no-heat and no-cool.","category":"general"}]},{"name":"HVAC - FAQ","content":"Common HVAC questions covered: maintenance frequency, system lifespan, financing, licensing, emergency service."}]'::jsonb, updated_at = now() WHERE industry_id = 'hvac';
